function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const replaced: number[] = new Array(n).fill(0);

    // Precompute the positions of '*' in the order
    const starPositions: number[] = [];
    for (let i = 0; i < n; i++) {
        starPositions.push(order[i]);
    }

    // Function to count the number of valid substrings
    function countValidSubstrings(): number {
        let count = 0;
        const stars = new Set(starPositions);
        for (let i = 0; i < n; i++) {
            if (stars.has(i)) {
                // For each star, count all substrings that include it
                // The number of substrings that include the i-th character is i * (n - i)
                count += i * (n - i);
            }
        }
        return count;
    }

    // Binary search for the minimum time t
    let left = 0, right = n;
    let result = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        // Replace first mid elements in order
        for (let i = 0; i < mid; i++) {
            replaced[order[i]] = 1;
        }

        // Count valid substrings with current replacements
        let validCount = 0;
        const stars = new Set<number>();
        for (let i = 0; i < n; i++) {
            if (replaced[i] === 1) {
                stars.add(i);
            }
        }

        for (let i = 0; i < n; i++) {
            if (stars.has(i)) {
                validCount += i * (n - i);
            }
        }

        if (validCount >= k) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }

        // Reset replaced array for next iteration
        for (let i = 0; i < n; i++) {
            replaced[i] = 0;
        }
    }

    return result;
}

